/**
 * @name Taint flow from HTTP URL/parameters to file system operations
 * @description Detects user-controlled input flowing to file system operations
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-retrofit
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // HTTP URL parameters in Retrofit context
    exists(MethodCall mc |
      mc.getMethod().hasName("url") or
      mc.getMethod().hasName("getPath") or
      mc.getMethod().hasName("getQuery") or
      mc.getMethod().hasName("encodedPath") or
      mc.getMethod().hasName("pathSegments") or
      mc.getMethod().hasName("encodedPathSegments")
      |
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // FileInputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileOutputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: data flows from $@ to file system operation.", source.getNode(), "HTTP input"

/**
 * @name URL construction with user input - potential SSRF or path traversal
 * @description Detects user-controlled data flowing into URL construction
 * @kind path-problem
 * @problem.severity error
 * @id java/url-construction-retrofit
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module UrlConstructionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // URL constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.net", "URL") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // HttpUrl.parse or HttpUrl.get
    exists(MethodCall mc |
      (mc.getMethod().hasName("parse") or mc.getMethod().hasName("get")) and
      mc.getMethod().getDeclaringType().hasQualifiedName("okhttp3", "HttpUrl") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // OkHttpClient request builder - url method
    exists(MethodCall mc |
      mc.getMethod().hasName("url") and
      mc.getMethod().getDeclaringType().hasQualifiedName("okhttp3", "Request$Builder") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module UrlConstructionFlow = TaintTracking::Global<UrlConstructionConfig>;
import UrlConstructionFlow::PathGraph

from UrlConstructionFlow::PathNode source, UrlConstructionFlow::PathNode sink
where UrlConstructionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "URL construction from $@.", source.getNode(), "remote input"

/**
 * @name External control of URL path via @Url annotation - no traversal validation
 * @description The @Url annotation value flows directly to HttpUrl.resolve() without path traversal validation.
 *              A caller can pass a URL with ../ sequences to escape the base URL path.
 * @kind path-problem
 * @problem.severity error
 * @id java/retrofit-url-annotation-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking

// Track value from RelativeUrl.apply parameter → setRelativeUrl → stored as relativeUrl field →
// → accessed in build() → passed to HttpUrl.resolve()
module UrlTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The 'value' parameter of RelativeUrl.apply - this is the @Url annotation value
    exists(Parameter p |
      p.getCallable().getDeclaringType().getName() = "RelativeUrl" and
      p.getCallable().getDeclaringType().getEnclosingType().hasQualifiedName("retrofit2", "ParameterHandler") and
      p.getCallable().getName() = "apply"
      |
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: argument to HttpUrl.resolve() in RequestBuilder.build()
    exists(MethodCall mc |
      mc.getMethod().hasName("resolve") and
      mc.getMethod().getDeclaringType().hasQualifiedName("okhttp3", "HttpUrl") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Sink: argument to setRelativeUrl
    exists(MethodCall mc |
      mc.getMethod().hasName("setRelativeUrl") and
      mc.getMethod().getDeclaringType().hasQualifiedName("retrofit2", "RequestBuilder")
      |
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module UrlTraversalFlow = TaintTracking::Global<UrlTraversalConfig>;
import UrlTraversalFlow::PathGraph

from UrlTraversalFlow::PathNode source, UrlTraversalFlow::PathNode sink
where UrlTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, 
  "Value annotated with @Url flows to $@ without path traversal validation - sequences like '../' can escape the base URL.",
  source.getNode(), "@Url parameter value"
